"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Button } from "../../components/ui/button";
import { Input } from "../../components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "../../components/ui/card";
import { ScrollArea } from "../../components/ui/scroll-area";
import { Avatar, AvatarFallback, AvatarImage } from "../../components/ui/avatar";
import { Hash, Send, Users, Settings } from "lucide-react";

const channels = [
  { id: "general", name: "general", type: "text" },
  { id: "sahara-fest", name: "sahara-fest", type: "text" },
  { id: "batch-2019", name: "batch-2019", type: "text" },
  { id: "batch-2020", name: "batch-2020", type: "text" },
  { id: "batch-2021", name: "batch-2021", type: "text" },
];

const messages = [
  {
    id: 1,
    user: "Rahul Sharma",
    avatar: "/memories/Acer_Wallpaper_01_3840x2400.jpg",
    content: "Hey everyone! Who's excited for Sahara Fest 2026?",
    timestamp: "2:30 PM",
  },
  {
    id: 2,
    user: "Priya Patel",
    avatar: "/memories/Acer_Wallpaper_02_3840x2400.jpg",
    content: "I am! Can't wait to see everyone again. It's been too long!",
    timestamp: "2:32 PM",
  },
  {
    id: 3,
    user: "Arun Kumar",
    avatar: "/memories/Acer_Wallpaper_03_3840x2400.jpg",
    content: "Same here! The countdown is killing me. Only 45 days left!",
    timestamp: "2:35 PM",
  },
  {
    id: 4,
    user: "Sneha Reddy",
    avatar: "/memories/Acer_Wallpaper_04_3840x2400.jpg",
    content: "Has anyone started planning their travel yet? I need recommendations for flights.",
    timestamp: "2:38 PM",
  },
];

const onlineUsers = [
  { name: "Rahul Sharma", avatar: "/memories/Acer_Wallpaper_01_3840x2400.jpg", status: "online" },
  { name: "Priya Patel", avatar: "/memories/Acer_Wallpaper_02_3840x2400.jpg", status: "online" },
  { name: "Arun Kumar", avatar: "/memories/Acer_Wallpaper_03_3840x2400.jpg", status: "away" },
  { name: "Sneha Reddy", avatar: "/memories/Acer_Wallpaper_04_3840x2400.jpg", status: "online" },
];

export default function ChatPage() {
  const [selectedChannel, setSelectedChannel] = useState("general");
  const [newMessage, setNewMessage] = useState("");

  const handleSendMessage = () => {
    if (newMessage.trim()) {
      // In a real app, this would send the message to the server
      console.log("Sending message:", newMessage);
      setNewMessage("");
    }
  };

  return (
    <div className="h-screen flex bg-gray-100">
      {/* Sidebar */}
      <div className="w-64 bg-gray-800 text-white flex flex-col">
        {/* Server Header */}
        <div className="p-4 border-b border-gray-700">
          <h1 className="text-lg font-semibold">Sahara Connect</h1>
        </div>

        {/* Channels */}
        <div className="flex-1 p-2">
          <div className="mb-4">
            <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2 px-2">
              Text Channels
            </h3>
            {channels.map((channel) => (
              <button
                key={channel.id}
                onClick={() => setSelectedChannel(channel.id)}
                className={`w-full text-left px-2 py-1 rounded mb-1 flex items-center gap-2 text-sm hover:bg-gray-700 transition-colors ${
                  selectedChannel === channel.id ? "bg-gray-700 text-white" : "text-gray-400"
                }`}
              >
                <Hash className="w-4 h-4" />
                {channel.name}
              </button>
            ))}
          </div>
        </div>

        {/* User Info */}
        <div className="p-2 border-t border-gray-700">
          <div className="flex items-center gap-2 p-2 rounded bg-gray-700">
            <Avatar className="w-8 h-8">
              <AvatarImage src="/memories/Acer_Wallpaper_01_3840x2400.jpg" />
              <AvatarFallback>RS</AvatarFallback>
            </Avatar>
            <div className="flex-1 min-w-0">
              <div className="text-sm font-medium text-white">Rahul Sharma</div>
              <div className="text-xs text-gray-400">#1234</div>
            </div>
            <Button variant="ghost" size="sm" className="h-8 w-8 p-0">
              <Settings className="w-4 h-4" />
            </Button>
          </div>
        </div>
      </div>

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col">
        {/* Chat Header */}
        <div className="h-12 bg-white border-b border-gray-200 flex items-center px-4">
          <Hash className="w-5 h-5 text-gray-500 mr-2" />
          <h2 className="font-semibold text-gray-800">{selectedChannel}</h2>
        </div>

        {/* Messages */}
        <ScrollArea className="flex-1 p-4">
          <div className="space-y-4">
            {messages.map((message) => (
              <motion.div
                key={message.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="flex gap-3"
              >
                <Avatar className="w-10 h-10">
                  <AvatarImage src={message.avatar} />
                  <AvatarFallback>{message.user[0]}</AvatarFallback>
                </Avatar>
                <div className="flex-1">
                  <div className="flex items-baseline gap-2 mb-1">
                    <span className="font-semibold text-gray-900">{message.user}</span>
                    <span className="text-xs text-gray-500">{message.timestamp}</span>
                  </div>
                  <p className="text-gray-700">{message.content}</p>
                </div>
              </motion.div>
            ))}
          </div>
        </ScrollArea>

        {/* Message Input */}
        <div className="p-4 border-t border-gray-200 bg-white">
          <div className="flex gap-2">
            <Input
              value={newMessage}
              onChange={(e) => setNewMessage(e.target.value)}
              placeholder={`Message #${selectedChannel}`}
              className="flex-1"
              onKeyPress={(e) => e.key === "Enter" && handleSendMessage()}
            />
            <Button onClick={handleSendMessage} size="sm">
              <Send className="w-4 h-4" />
            </Button>
          </div>
        </div>
      </div>

      {/* Online Users Sidebar */}
      <div className="w-60 bg-gray-50 border-l border-gray-200 flex flex-col">
        <div className="p-4 border-b border-gray-200">
          <h3 className="font-semibold text-gray-800 flex items-center gap-2">
            <Users className="w-5 h-5" />
            Online ΓÇö {onlineUsers.filter(u => u.status === "online").length}
          </h3>
        </div>

        <ScrollArea className="flex-1 p-2">
          <div className="space-y-2">
            {onlineUsers.map((user) => (
              <div key={user.name} className="flex items-center gap-2 p-2 rounded hover:bg-gray-100">
                <div className="relative">
                  <Avatar className="w-8 h-8">
                    <AvatarImage src={user.avatar} />
                    <AvatarFallback>{user.name[0]}</AvatarFallback>
                  </Avatar>
                  <div className={`absolute -bottom-1 -right-1 w-3 h-3 rounded-full border-2 border-white ${
                    user.status === "online" ? "bg-green-500" : "bg-yellow-500"
                  }`} />
                </div>
                <span className="text-sm font-medium text-gray-700">{user.name}</span>
              </div>
            ))}
          </div>
        </ScrollArea>
      </div>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import Link from "next/link";
import { Button } from "./ui/button";
import { Container } from "./layout/Container";

export default function Navbar() {
  return (
    <motion.nav
      className="fixed top-0 w-full z-50 bg-background/80 backdrop-blur-md text-foreground border-b border-border shadow-sm"
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.6 }}
    >
      <Container className="flex justify-between items-center py-4">
        <motion.div
          className="text-xl font-bold text-foreground"
          whileHover={{ scale: 1.05 }}
        >
          Sahara Connect
        </motion.div>

        <div className="hidden md:flex space-x-8 text-sm font-medium">
          {["About", "Batches", "Alumni"].map((item, index) => (
            <motion.a
              key={item}
              href="#"
              className="text-foreground/80 hover:text-primary transition-colors duration-300"
              whileHover={{ scale: 1.1 }}
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
            >
              {item}
            </motion.a>
          ))}
        </div>

        <div className="flex space-x-4">
          <Button
            variant="ghost"
            className="text-foreground hover:text-primary hover:bg-muted"
          >
            Login
          </Button>
          <Button className="rounded-full shadow-md">
            Join Now
          </Button>
        </div>
      </Container>
    </motion.nav>
  );
}

"use client";

import { motion } from "framer-motion";
import Image from "next/image";

import { Section } from "@/components/layout/Section";
import { Container } from "@/components/layout/Container";

const aboutImages = [
  "/memories/Acer_Wallpaper_01_3840x2400.jpg",
  "/memories/Acer_Wallpaper_02_3840x2400.jpg",
  "/memories/Acer_Wallpaper_03_3840x2400.jpg",
  "/memories/Acer_Wallpaper_04_3840x2400.jpg",
];

export default function AboutSection() {
  return (
    <Section className="bg-secondary/50">
      <Container>
        <div className="grid lg:grid-cols-2 gap-16 items-center">
          {/* Text Content */}
          <motion.div
            initial={{ opacity: 0, x: -50 }}
            whileInView={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8 }}
            viewport={{ once: true }}
          >
            <h2 className="text-4xl md:text-5xl font-serif font-bold text-foreground mb-8">
              About <span className="text-primary tracking-tight">Sahara</span>
            </h2>

            <div className="space-y-6 text-lg text-muted-foreground leading-relaxed">
              <p>
                Sahara Hostel isn&apos;t just a place to stayΓÇöit&apos;s where lifelong bonds are forged.
                From late-night conversations that turn into lifelong friendships, to shared
                adventures that create unforgettable memories, Sahara represents the essence
                of brotherhood and community.
              </p>

              <p>
                Our alumni network spans across the globe, working in diverse fields,
                yet united by the common thread of having called Sahara home. Whether
                you're a recent graduate or someone who stayed decades ago, the spirit
                of Sahara lives on in each of us.
              </p>

              <p>
                Through Sahara Connect, we maintain these connections, celebrate our
                shared history, and continue to support each other's journeys forward.
              </p>
            </div>
          </motion.div>

          {/* Image Grid */}
          <motion.div
            className="grid grid-cols-2 gap-4"
            initial={{ opacity: 0, x: 50 }}
            whileInView={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8, delay: 0.2 }}
            viewport={{ once: true }}
          >
            {aboutImages.map((img, i) => (
              <motion.div
                key={i}
                className="relative h-48 rounded-2xl overflow-hidden shadow-md ring-1 ring-border"
                whileHover={{ scale: 1.05, rotate: 2 }}
                transition={{ duration: 0.3 }}
              >
                <Image
                  src={img}
                  fill
                  className="object-cover"
                  alt={`Sahara memory ${i + 1}`}
                />
              </motion.div>
            ))}
          </motion.div>
        </div>
      </Container>
    </Section>
  );
}

"use client";

import { motion } from "framer-motion";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { MapPin, Briefcase } from "lucide-react";

import { Section } from "@/components/layout/Section";
import { Container } from "@/components/layout/Container";

const alumni = [
  {
    name: "Rahul Sharma",
    role: "Senior Software Engineer",
    company: "Google",
    location: "Bangalore, India",
    image: "/memories/Acer_Wallpaper_01_3840x2400.jpg",
    batch: "2015",
  },
  {
    name: "Priya Patel",
    role: "Product Manager",
    company: "Microsoft",
    location: "Seattle, USA",
    image: "/memories/Acer_Wallpaper_02_3840x2400.jpg",
    batch: "2016",
  },
  {
    name: "Arun Kumar",
    role: "Entrepreneur",
    company: "TechStart Inc.",
    location: "Mumbai, India",
    image: "/memories/Acer_Wallpaper_03_3840x2400.jpg",
    batch: "2017",
  },
  {
    name: "Sneha Reddy",
    role: "Data Scientist",
    company: "Amazon",
    location: "New York, USA",
    image: "/memories/Acer_Wallpaper_04_3840x2400.jpg",
    batch: "2018",
  },
];

export default function AlumniSpotlightSection() {
  return (
    <Section className="bg-secondary/30 border-y border-border">
      <Container>
        <motion.div
          className="text-center mb-16"
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
        >
          <h2 className="text-4xl md:text-5xl font-serif font-bold text-foreground mb-6">
            Alumni <span className="text-primary tracking-tight">Spotlight</span>
          </h2>
          <p className="text-xl text-muted-foreground max-w-3xl mx-auto">
            Meet some of our remarkable alumni who are making waves in their fields.
            Their journeys inspire us all to reach greater heights.
          </p>
        </motion.div>

        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">
          {alumni.map((person, index) => (
            <motion.div
              key={person.name}
              initial={{ opacity: 0, y: 50 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: index * 0.1 }}
              viewport={{ once: true }}
            >
              <Card className="group hover:shadow-2xl transition-all duration-500 border border-border shadow-md bg-card overflow-hidden h-full">
                <div className="relative h-48 overflow-hidden grayscale group-hover:grayscale-0 transition-all duration-700">
                  <img
                    src={person.image}
                    alt={person.name}
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                  />
                  <div className="absolute top-4 right-4">
                    <Badge className="bg-primary text-primary-foreground font-semibold shadow-sm">
                      Batch {person.batch}
                    </Badge>
                  </div>
                </div>

                <CardContent className="p-6">
                  <h3 className="text-xl font-serif font-bold text-foreground mb-2">
                    {person.name}
                  </h3>

                  <div className="space-y-2 text-muted-foreground">
                    <div className="flex items-center gap-2">
                      <Briefcase className="w-4 h-4 text-primary" />
                      <span className="font-semibold text-foreground/90">{person.role}</span>
                    </div>

                    <div className="text-sm font-medium text-primary">
                      {person.company}
                    </div>

                    <div className="flex items-center gap-2 text-sm">
                      <MapPin className="w-4 h-4" />
                      <span>{person.location}</span>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          ))}
        </div>
      </Container>
    </Section>
  );
}

"use client";

import { Section } from "@/components/layout/Section";
import { Container } from "@/components/layout/Container";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Users, Calendar, Heart } from "lucide-react";

const batches = [
  {
    year: "2015",
    members: 45,
    active: 32,
    color: "from-primary/90 to-primary",
    avatars: ["/memories/Acer_Wallpaper_01_3840x2400.jpg", "/memories/Acer_Wallpaper_02_3840x2400.jpg", "/memories/Acer_Wallpaper_03_3840x2400.jpg"],
    backgroundImage: "/memories/Acer_Wallpaper_01_3840x2400.jpg",
  },
  {
    year: "2016",
    members: 52,
    active: 41,
    color: "from-primary/80 to-primary/90",
    avatars: ["/memories/Acer_Wallpaper_02_3840x2400.jpg", "/memories/Acer_Wallpaper_03_3840x2400.jpg", "/memories/Acer_Wallpaper_04_3840x2400.jpg"],
    backgroundImage: "/memories/Acer_Wallpaper_02_3840x2400.jpg",
  },
  {
    year: "2017",
    members: 38,
    active: 29,
    color: "from-primary/70 to-primary/80",
    avatars: ["/memories/Acer_Wallpaper_03_3840x2400.jpg", "/memories/Acer_Wallpaper_04_3840x2400.jpg", "/memories/Acer_Wallpaper_05_3840x2400.jpg"],
    backgroundImage: "/memories/Acer_Wallpaper_03_3840x2400.jpg",
  },
  {
    year: "2018",
    members: 61,
    active: 48,
    color: "from-primary/60 to-primary/70",
    avatars: ["/memories/Acer_Wallpaper_01_3840x2400.jpg", "/memories/Acer_Wallpaper_04_3840x2400.jpg", "/memories/Acer_Wallpaper_05_3840x2400.jpg"],
    backgroundImage: "/memories/Acer_Wallpaper_04_3840x2400.jpg",
  },
];

export default function BatchNetworkSection() {
  return (
    <Section className="bg-background">
      {/* Background Pattern */}
      <div className="absolute inset-0 opacity-[0.03] dark:opacity-[0.05] pointer-events-none">
        <div className="absolute inset-0" style={{
          backgroundImage: `url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23000000' fill-opacity='1'%3E%3Ccircle cx='30' cy='30' r='2'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E")`,
        }} />
      </div>

      {/* Floating Elements */}
      <div className="absolute top-20 left-10 w-20 h-20 bg-primary/10 rounded-full blur-xl animate-pulse" style={{ animationDelay: '0s' }} />
      <div className="absolute top-40 right-20 w-16 h-16 bg-accent/10 rounded-full blur-xl animate-pulse" style={{ animationDelay: '1s' }} />
      <div className="absolute bottom-20 left-1/4 w-12 h-12 bg-primary/10 rounded-full blur-xl animate-pulse" style={{ animationDelay: '2s' }} />

      <Container>
        <motion.div
          className="text-center mb-20"
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          viewport={{ once: true }}
        >
          <motion.div
            className="inline-block p-4 bg-primary rounded-2xl mb-6 shadow-md"
            whileHover={{ scale: 1.05 }}
          >
            <Users className="w-8 h-8 text-primary-foreground" />
          </motion.div>
          <h2 className="text-4xl md:text-6xl font-serif font-bold text-foreground mb-6">
            Batch <span className="text-primary tracking-tight">Network</span>
          </h2>
          <p className="text-xl text-muted-foreground max-w-3xl mx-auto leading-relaxed">
            Connect with your batchmates and relive the memories that shaped your journey.
            Each batch represents a unique chapter in Sahara&apos;s legendary story.
          </p>
        </motion.div>

        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">
          {batches.map((batch, index) => (
            <motion.div
              key={batch.year}
              initial={{ opacity: 0, y: 50, scale: 0.9 }}
              whileInView={{ opacity: 1, y: 0, scale: 1 }}
              transition={{ duration: 0.6, delay: index * 0.15 }}
              viewport={{ once: true }}
              whileHover={{ y: -10 }}
            >
              <Card className="group relative overflow-hidden border border-border shadow-sm hover:shadow-xl transition-all duration-500 h-full bg-card">
                {/* Background Image Overlay */}
                <div className="absolute inset-0 opacity-[0.05] group-hover:opacity-[0.15] transition-opacity duration-500 grayscale">
                  <img
                    src={batch.backgroundImage}
                    alt={`Batch ${batch.year} memories`}
                    className="w-full h-full object-cover"
                  />
                </div>

                {/* Gradient Overlay */}
                <div className={`absolute inset-0 bg-gradient-to-br ${batch.color} opacity-0 group-hover:opacity-5 transition-opacity duration-500`} />

                <CardHeader className="text-center pb-4 relative z-10">
                  <motion.div
                    className={`w-20 h-20 bg-gradient-to-br ${batch.color} rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg group-hover:scale-110 group-hover:rotate-6 transition-all duration-500`}
                    whileHover={{ rotate: 360 }}
                    transition={{ duration: 0.6 }}
                  >
                    <Calendar className="w-10 h-10 text-primary-foreground" />
                  </motion.div>

                  <CardTitle className="text-3xl font-serif text-foreground mb-2 group-hover:text-primary transition-colors duration-300">
                    {batch.year}
                  </CardTitle>
                </CardHeader>

                <CardContent className="text-center space-y-4 relative z-10">
                  <div className="grid grid-cols-2 gap-4 text-sm">
                    <div className="bg-secondary rounded-xl p-3 ring-1 ring-border/50">
                      <Users className="w-4 h-4 text-foreground mx-auto mb-1" />
                      <div className="font-bold text-foreground">{batch.members}</div>
                      <div className="text-muted-foreground text-xs">Total</div>
                    </div>
                    <div className="bg-secondary/50 rounded-xl p-3 ring-1 ring-border/50">
                      <div className="w-4 h-4 bg-emerald-500/80 rounded-full mx-auto mb-1 ring-2 ring-emerald-500/20"></div>
                      <div className="font-bold text-foreground">{batch.active}</div>
                      <div className="text-muted-foreground text-xs">Active</div>
                    </div>
                  </div>

                  {/* Enhanced Avatar Stack */}
                  <div className="flex justify-center -space-x-3 mb-4">
                    {batch.avatars.map((avatar, i) => (
                      <motion.div
                        key={i}
                        className="w-10 h-10 rounded-full border-2 border-background overflow-hidden shadow-sm"
                        whileHover={{ scale: 1.2, zIndex: 10 }}
                        transition={{ duration: 0.2 }}
                      >
                        <img
                          src={avatar}
                          alt={`Member ${i + 1}`}
                          className="w-full h-full object-cover"
                        />
                      </motion.div>
                    ))}
                    <div className="w-10 h-10 rounded-full bg-muted border-2 border-background flex items-center justify-center text-muted-foreground text-xs font-bold shadow-sm">
                      +{batch.members - 3}
                    </div>
                  </div>

                  <Button
                    size="sm"
                    className={`w-full bg-gradient-to-r ${batch.color} hover:opacity-90 text-primary-foreground font-semibold rounded-full group-hover:scale-[1.02] transition-all duration-300`}
                  >
                    <Heart className="w-4 h-4 mr-2" />
                    Connect
                  </Button>
                </CardContent>
              </Card>
            </motion.div>
          ))}
        </div>

        {/* Bottom CTA */}
        <motion.div
          className="text-center mt-16"
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.5 }}
          viewport={{ once: true }}
        >
          <p className="text-muted-foreground mb-6">Can&apos;t find your batch? Help us grow the network!</p>
          <Button className="font-semibold px-8 py-6 rounded-full shadow-lg hover:shadow-xl transition-all duration-300 transform hover:scale-105">
            Add Your Batch
          </Button>
        </motion.div>
      </Container>
    </Section>
  );
}
